#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int N = strlen(S);
        int time = 0;
        for (int i = 0; i < N; i++) {
            if (S[i] == '1') {
                int j = i + 1;
                while (j < N && S[j] == '0') {
                    j++;
                }
                time += j - i;
                for (int k = i; k < j; k++) {
                    S[k] = '0';
                }
                S[j] = '1';
            }
        }
        printf("%d\n", time);
    }
    return 0;
}

