import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int N = S.length();
            int time = 0;
            char[] arr = S.toCharArray();
            for (int i = 0; i < N; i++) {
                if (arr[i] == '1') {
                    int j = i + 1;
                    while (j < N && arr[j] == '0') {
                        j++;
                    }
                    time += j - i;
                    for (int k = i; k < j; k++) {
                        arr[k] = '0';
                    }
                    arr[j] = '1';
                }
            }
            System.out.println(time);
        }
    }
}

